class Solution {
    public int countLargestGroup(int n) {
        int[] count = new int[37]; // maximum sum of digits for n <= 10^4 is 9*4 = 36
        int maxCount = 0, result = 0;
        for (int i = 1; i <= n; i++) {
            int sum = 0, num = i;
            while (num > 0) {
                sum += num % 10;
                num /= 10;
            }
            count[sum]++;
            if (count[sum] > maxCount) {
                maxCount = count[sum];
                result = 1;
            } else if (count[sum] == maxCount) {
                result++;
            }
        }
        return result;
    }
}
